    // ====== PC-2 Table: 56 -> 48 bits (round subkey) ======
    private static final int[] PC2 = {
        14, 17, 11, 24,  1,  5,
         3, 28, 15,  6, 21, 10,
        23, 19, 12,  4, 26,  8,
        16,  7, 27, 20, 13,  2,
        41, 52, 31, 37, 47, 55,
        30, 40, 51, 45, 33, 48,
        44, 49, 39, 56, 34, 53,
        46, 42, 50, 36, 29, 32
    };

    // ====== Left-Shift Schedule for key schedule ======
    private static final int[] SHIFTS = {
        1, 1, 2, 2, 2, 2, 2, 2,
        1, 2, 2, 2, 2, 2, 2, 1
    };
```

> [!NOTE]
> **Bit-Numbering Convention:** In DES tables above, bit `1` is the **MSB** of the block. The tables are 1-indexed (as in the FIPS spec). In the Java code below, we use a 0-indexed `BitSet` and shift accordingly: a table value of $i$ corresponds to position $64 - i$ in a 64-bit `BitSet`.

### 📦 Block 2: Permutation Helper (Generic, Table-Driven)

```java
    // Generic permutation: permutes `input` (BitSet of size 'inSize')
    // according to `table`, producing a BitSet of size `outSize`.
    private static BitSet permute(BitSet input, int[] table, int inSize, int outSize) {
        BitSet output = new BitSet(outSize);
        for (int i = 0; i < table.length; i++) {
            // Convert 1-indexed FIPS position to 0-indexed BitSet position
            int from = inSize - table[i];
            int to   = outSize - 1 - i;
            if (input.get(from)) {
                output.set(to);
            }
        }
        return output;
    }
```

> [!NOTE]
> **Why `inSize - table[i]`?** DES tables are 1-indexed from the **left (MSB)**. A `BitSet` is 0-indexed from the **LSB**. We invert the order so that `table[0]` (e.g., 58) becomes the highest bit of input mapped to bit 0 of output's "logical MSB view."

### 📦 Block 3: The Round Function $f(R, K)$

```java
    // The Feistel round function f(R, K)
    private static BitSet feistel(BitSet R, BitSet K) {
        // Step 1: Expand R from 32 -> 48 bits using E-table
        BitSet expanded = permute(R, E, 32, 48);

        // Step 2: XOR expanded R with the 48-bit round subkey
        expanded.xor(K);

        // Step 3: S-Box substitution: 48 -> 32 bits
        BitSet sBoxOut = new BitSet(32);
        for (int i = 0; i < 8; i++) {
            // Extract 6-bit chunk
            int row = (getBit(expanded, i*6)   ? 2 : 0) |
                      (getBit(expanded, i*6+5) ? 1 : 0);
            int col = 0;
            for (int j = 1; j <= 4; j++) {
                if (getBit(expanded, i*6 + j)) col |= (1 << (4 - j));
            }
            int val = S[i][row][col];

            // Write 4-bit S-box output
            for (int b = 0; b < 4; b++) {
                if ((val & (1 << (3 - b))) != 0) {
                    sBoxOut.set(31 - (i*4 + b));
                }
            }
        }

        // Step 4: Apply P-permutation
        return permute(sBoxOut, P, 32, 32);
    }

    // Helper: read a single bit from a BitSet
    private static boolean getBit(BitSet bs, int pos) {
        return bs.get(pos);
    }
```

> [!IMPORTANT]
> **Algebraic walkthrough of $f(R, K)$:**
>
> $$
> f(R, K) = P\left( S_1(S_2(\cdots S_8(E(R) \oplus K)))\right)
> $$
>
> - $E(R)$: Expansion maps $R \in \{0,1\}^{32} \to \{0,1\}^{48}$.
> - $E(R) \oplus K$: bitwise XOR.
> - $S_j$ takes the $j$-th 6-bit group, splits into row (2 bits, MSB+LSB) and column (4 middle bits), and outputs 4 bits via the S-box table. **This is the only nonlinear step of DES.**
> - $P$ reorders the 32 bits.

### 📦 Block 4: Key Schedule — Generating 16 Round Subkeys

```java
    // Generate 16 round subkeys from a 64-bit master key
    private static BitSet[] generateSubkeys(BitSet key64) {
        // Step 1: PC-1 (drop parity bits) -> 56-bit key
        BitSet key56 = permute(key64, PC1, 64, 56);

        // Split into two 28-bit halves
        BitSet C = key56.get(0, 28);
        BitSet D = key56.get(28, 56);

        BitSet[] subkeys = new BitSet[16];

        for (int i = 0; i < 16; i++) {
            // Circular left shift on both halves
            C = leftShift(C, 28, SHIFTS[i]);
            D = leftShift(D, 28, SHIFTS[i]);

            // Concatenate C and D into a 56-bit BitSet
            BitSet CD = new BitSet(56);
            for (int b = 0; b < 28; b++) {
                if (C.get(b)) CD.set(b);
                if (D.get(b)) CD.set(b + 28);
            }

            // PC-2: select 48 bits -> round subkey
            subkeys[i] = permute(CD, PC2, 56, 48);
        }
        return subkeys;
    }

    // Circular left shift on a `size`-bit BitSet by 'n' positions
    private static BitSet leftShift(BitSet bs, int size, int n) {
        BitSet result = new BitSet(size);
        for (int i = 0; i < size; i++) {
            int newPos = (i + n) % size;
            if (bs.get(i)) result.set(newPos);
        }
        return result;
    }
```

> [!NOTE]
> **Algebraic Form of the Key Schedule:**
> For each round $i = 1, 2, \dots, 16$:
> $$
> C_i = \sigma^{s_i}(C_{i-1}), \quad D_i = \sigma^{s_i}(D_{i-1})
> $$
> $$
> K_i = PC_2(C_i \vert D_i)
> $$
> where $\sigma^{s_i}$ denotes a circular left shift by $s_i$ bits (per the SHIFTS table), and $C_0 \vert D_0 = PC_1(K)$.

### 📦 Block 5: The Main DES Encryption/Decryption Routine

```java
    // DES Encryption: 64-bit plaintext + 64-bit key -> 64-bit ciphertext
    public static BitSet encrypt(BitSet plaintext, BitSet key) {
        BitSet[] subkeys = generateSubkeys(key);

        // Step 1: Initial Permutation
        BitSet ip = permute(plaintext, IP, 64, 64);

        // Step 2: Split into L and R (32 bits each)
        BitSet L = ip.get(0, 32);
        BitSet R = ip.get(32, 64);

        // Step 3: 16 Feistel rounds
        for (int i = 0; i < 16; i++) {
            BitSet newL = R;
            BitSet fOut = feistel(R, subkeys[i]);
            fOut.xor(L);
            L = newL;
            R = fOut;
        }

        // Step 4: Swap L and R (note: NOT undoing the swap from round 16)
        BitSet preOutput = new BitSet(64);
        for (int b = 0; b < 32; b++) {
            if (R.get(b)) preOutput.set(b);
            if (L.get(b)) preOutput.set(b + 32);
        }

        // Step 5: Inverse Initial Permutation
        return permute(preOutput, IP_INV, 64, 64);
    }

    // DES Decryption: same algorithm, but subkeys used in REVERSE order
    public static BitSet decrypt(BitSet ciphertext, BitSet key) {
        BitSet[] subkeys = generateSubkeys(key);

        BitSet ip = permute(ciphertext, IP, 64, 64);
        BitSet L = ip.get(0, 32);
        BitSet R = ip.get(32, 64);

        for (int i = 15; i >= 0; i--) {       // <-- REVERSE ORDER
            BitSet newL = R;
            BitSet fOut = feistel(R, subkeys[i]);
            fOut.xor(L);
            L = newL;
            R = fOut;
        }

        BitSet preOutput = new BitSet(64);
        for (int b = 0; b < 32; b++) {
            if (R.get(b)) preOutput.set(b);
            if (L.get(b)) preOutput.set(b + 32);
        }

        return permute(preOutput, IP_INV, 64, 64);
    }
```

> [!IMPORTANT]
> **Decryption Symmetry — The Feistel Magic:**
> Decryption is **identical** to encryption except that the subkeys are applied in **reverse order** (i.e., $K_{16}, K_{15}, \dots, K_1$). This is the **defining elegance** of the Feistel structure: the same hardware/software can both encrypt and decrypt — only the key schedule direction changes.

### 📦 Block 6: `main()` Method — Driver Program with I/O

```java
    // ====== Utility: Convert a hex string to a 64-bit BitSet ======
    private static BitSet hexToBitSet(String hex, int bits) {
        BitSet bs = new BitSet(bits);
        long val = Long.parseUnsignedLong(hex, 16);
        for (int i = 0; i < bits; i++) {
            if (((val >> (bits - 1 - i)) & 1) == 1) {
                bs.set(i);
            }
        }
        return bs;
    }

    // ====== Utility: Convert a 64-bit BitSet to a hex string ======
    private static String bitSetToHex(BitSet bs, int bits) {
        long val = 0L;
        for (int i = 0; i < bits; i++) {
            if (bs.get(i)) val |= (1L << (bits - 1 - i));
        }
        return String.format("%016X", val);
    }

    // ====== Main Driver ======
    public static void main(String[] args) {
        // FIPS Standard Test Vector:
        // Plaintext = 0123456789ABCDEF, Key = 133457799BBCDFF1
        // Expected Ciphertext = 85E813540F0AB405
        String ptHex = "0123456789ABCDEF";
        String keyHex = "133457799BBCDFF1";

        BitSet plaintext = hexToBitSet(ptHex, 64);
        BitSet key       = hexToBitSet(keyHex, 64);

        System.out.println("Plaintext  : " + ptHex);
        System.out.println("Key        : " + keyHex);

        BitSet ciphertext = encrypt(plaintext, key);
        System.out.println("Ciphertext : " + bitSetToHex(ciphertext, 64));

        BitSet recovered  = decrypt(ciphertext, key);
        System.out.println("Decrypted  : " + bitSetToHex(recovered, 64));
    }
}
```

### 📊 Expected Output (Verified Against FIPS Test Vector)

```
Plaintext  : 0123456789ABCDEF
Key        : 133457799BBCDFF1
Ciphertext : 85E813540F0AB405
Decrypted  : 0123456789ABCDEF
```

